SELECT user_type, COUNT(user_type) AS user_type_count
FROM users
GROUP BY user_type;

SELECT official_name, official_email
FROM city_officials
ORDER BY official_name;

SELECT COUNT(DISTINCT city_name)
FROM cities
WHERE city_location IN ('East', 'West', 'North', 'South');

SELECT cities.city_name, city_officials.official_name
FROM cities
INNER JOIN city_officials ON cities.city_name = city_officials.official_name;

SELECT COUNT(*)
FROM urban_planners
WHERE planner_phone LIKE '123%' OR planner_email LIKE '%@urbanplanning.com';
